from typing import List

class SummaryRanges:

    def __init__(self):
        self.intervals = []

    def addNum(self, value: int) -> None:
        if not self.intervals:
            self.intervals.append([value, value])
            return

        left, right = 0, len(self.intervals) - 1
        while left <= right:
            mid = (left + right) // 2
            if self.intervals[mid][0] <= value <= self.intervals[mid][1]:
                return
            elif self.intervals[mid][1] < value:
                left = mid + 1
            else:
                right = mid - 1

        if left == 0:
            if self.intervals[0][0] - 1 == value:
                self.intervals[0][0] = value
            else:
                self.intervals.insert(0, [value, value])
        elif left == len(self.intervals):
            if self.intervals[-1][1] + 1 == value:
                self.intervals[-1][1] = value
            else:
                self.intervals.append([value, value])
        else:
            if self.intervals[left - 1][1] + 1 == value:
                self.intervals[left - 1][1] = value
            elif self.intervals[left][0] - 1 == value:
                self.intervals[left][0] = value
            else:
                self.intervals.insert(left, [value, value])

        self.mergeIntervals()

    def getIntervals(self) -> List[List[int]]:
        return self.intervals

    def mergeIntervals(self):
        i = 1
        while i < len(self.intervals):
            if self.intervals[i - 1][1] >= self.intervals[i][0]:
                self.intervals[i - 1][1] = max(self.intervals[i - 1][1], self.intervals[i][1])
                self.intervals.pop(i)
            else:
                i += 1


